(function(){
  PyLearn.createEditor({
    containerId: 'editor-sum',
    initialCode: '# Add up 1 to 100 using a for loop\ntotal = 0\n# your loop here\nprint(total)',
    label: 'Challenge',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };
      if (!output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing printed yet.' };
      if (output.trim() !== '5050') return { pass: false, message: '\u274c Got ' + output.trim() + ' \u2014 expected 5050.' };
      if (!/for/.test(code) && !/while/.test(code)) return { pass: false, message: '\u26a0\ufe0f Correct answer, but please use a loop.' };
      return { pass: true, message: '\u2705 Correct! The sum of 1\u2013100 is 5050.' };
    },
    onPass: async function() { await window.__markStepComplete(); }
  });
})();

